INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('680280d2e3c98b0941765e16', '花园酒店的客房和员工的服务都非常不错，很满意的一次出行！Mikey很热情，以后还会回来住！', '["https://dimg04.c-ctrip.com/images/0234g12000arv8zyl5702_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000arv8e3e13C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000arv93zoD4B6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-15', '红棉大床套房', '套房', '商务出差', 45, 0, 5, 6, '["整体满意度","客房服务"]'::jsonb, '整体满意度', '客房服务', NULL),
('680280d2e3c98b0941765e17', '位置比较好，服务也可以，周边有很多好吃的，就是酒店时间比较久，房间有点旧人也多，晚上11点了办理入住感觉都还要排队', '["https://dimg04.c-ctrip.com/images/0234b12000aoyp0klA4CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000aoysk4mB501_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000aoyrhqf0DEF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-02-20', '城央绿意大床房', '大床房', '家庭亲子', 57, 0, 34, 7, '["周边配套","退房/入住效率","房间设施"]'::jsonb, '周边配套', '退房/入住效率', '房间设施'),
('680280dce3c98b0941765e19', '酒店大堂接待很好 就是排队太长了 二楼中餐厅出品太差了 应该提高 完全不是原来的水平  三楼桃源还可以 出菜速度应该提高', '["https://dimg04.c-ctrip.com/images/0234w12000anvhudn6750_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000anvlpscCDCB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000anvlkxt29A1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-02-13', '花园大床房', '大床房', '商务出差', 60, 0, 31, 6, '["前台服务","餐饮设施","退房/入住效率"]'::jsonb, '前台服务', '餐饮设施', '退房/入住效率'),
('680280dce3c98b0941765e1a', '办理入住的时候Yedda给小朋友送了酒店自制的小点心，还给我们升级了房间，房间干净整洁，周边有名的广式早茶距离都很近，超棒！', '["https://dimg04.c-ctrip.com/images/0232g12000as0v6bzE047_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000as0zx8n4D3C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000as0y73k0D6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000as11t4cCF21_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000as0rf1v08F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000as0yabt6F27_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000as0wxye70D5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-16', '花园大床房', '大床房', '家庭亲子', 62, 0, 14, 8, '["前台服务","周边配套","整体满意度"]'::jsonb, '前台服务', '周边配套', '整体满意度'),
('680280dce3c98b0941765e1b', '每次出差必选的酒店，服务特别好，这次早上就到了酒店前台找到有空房直接给提前入住了，特别感谢酒店的人性化服务', '["https://dimg04.c-ctrip.com/images/0232012000ap63es1AA00_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-21', '花园大床房', '大床房', '商务出差', 53, 0, 3, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680280dce3c98b0941765e1c', '美食加美景，不愧是广州老牌的五星酒店，软件服务比硬件更胜一筹，下回有机会一定再次入住，五星好评!', '["https://dimg04.c-ctrip.com/images/0231m12000aqai6m9C4BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000aqahy4b5075_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000aqahrow74E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000aqajqo61FC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000aqai8nq6DC0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000aqajtq61390_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-02', '花园双床房', '双床房', '商务出差', 48, 0, 104, 6, '["整体满意度","餐饮设施","景观/朝向"]'::jsonb, '整体满意度', '餐饮设施', '景观/朝向'),
('680280dce3c98b0941765e1d', '很高兴这次来广州选择了花园酒店～ 很有历史沉淀感的酒店，后花园非常漂亮，名副其实的花园酒店，Billy替我们办理了原房续住省去了我们换房间的麻烦，特别感恩感谢～ 感受到了广州人民的友好与好客，会推荐以后来广州的朋友入住此酒店～', '["https://dimg04.c-ctrip.com/images/0233l12000c3iyezfF0A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000c3j09kaAAE0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000c3izrfw562D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-09', '红棉大床套房', '套房', '家庭亲子', 113, 0, 1, 7, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('680280dce3c98b0941765e1e', '推荐推荐，还是很好的，赞????，比较适合商旅客人入住的酒店，短暂的体验岭南文化，酒店设计的文化植入点恰到好处', '["https://dimg04.c-ctrip.com/images/0236e12000ap4kxxn03DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000ap4p0ki981D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000ap4m4vrCCFF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000ap4mnqy26EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000ap4hnwo0D76_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000ap4ldhq711A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000ap4ojln55D1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000ap4idq8E96C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-21', '城央绿意双床房', '双床房', '商务出差', 55, 0, 16, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('680280dce3c98b0941765e1f', '来过几次了，这个价钱有个套房就真的很值，而且前台小姐姐超有礼貌。不过停车不太方便，没有独立化妆台和全身镜，可以改进', '["https://dimg04.c-ctrip.com/images/0234i12000anqik7tD5BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236312000anqinpg2FF1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000anqijm90F92_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000anqinpl0BCD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000anqioptA017_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000anqip3k15CB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-12', '红棉大床套房', '套房', '情侣出游', 57, 0, 6, 7, '["性价比","前台服务","房间设施"]'::jsonb, '性价比', '前台服务', '房间设施'),
('680280dce3c98b0941765e20', '广州老牌五星级酒店，服务态度很好??，入住当天因为是38节，还有??送喔，里面有网红打卡地瀑布餐厅????', '["https://dimg04.c-ctrip.com/images/0236612000b6cdhaeDF39_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000b6cdkm351E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000b6cazb355F4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-07', '城央绿意双床房', '双床房', '朋友出游', 53, 0, 6, 6, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('680280dde3c98b0941765e21', '大堂和公共区域很美，不错，唯独房间略小，卫生间和浴室公用一个移门，也是很尴尬，只适合家庭游。离地铁站很近，交通还算方便', '["https://dimg04.c-ctrip.com/images/0233y12000aqu10y07524_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000aqu4frtD082_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000aqu2pngD38F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-03-06', '花园双床房', '双床房', '家庭亲子', 59, 0, 10, 6, '["房间设施","交通便利性","公共设施"]'::jsonb, '房间设施', '交通便利性', '公共设施'),
('680280e8e3c98b0941765e22', '很不错，大堂很美', '["https://dimg04.c-ctrip.com/images/0235q12000b96hgrh8C88_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-19', '花园双床房', '双床房', '朋友出游', 8, 0, 10, 3, '["公共设施"]'::jsonb, '公共设施', NULL, NULL),
('680280e8e3c98b0941765e23', '酒店很漂亮，环境很好，交通便利，逛街很方便', '["https://dimg04.c-ctrip.com/images/0236h12000b93grfcB2B0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-19', '花园大床房', '大床房', '朋友出游', 21, 0, 5, 4, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('680280e8e3c98b0941765e24', '不愧是广州第一家五星级酒店，服务满分，餐食满分，环境也很好，临街也不吵，床品没有异味，没想到在酒店睡的这么踏实，强力推荐，秒杀网红酒店。', '["https://dimg04.c-ctrip.com/images/0237112000ahl1a3kB45E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000ahl1ul7BECA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000ahkz6c2752A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-22', '花园大床房', '大床房', '独自旅行', 68, 0, 2, 8, '["整体满意度","安静程度","卫生状况"]'::jsonb, '整体满意度', '安静程度', '卫生状况'),
('680280e8e3c98b0941765e25', '房间干净 很不错 
第二次入住', '["https://dimg04.c-ctrip.com/images/0235b2224uxkelbxd3007_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-30', '花园双床房', '双床房', '家庭亲子', 15, 0, 9, 3, '["卫生状况","整体满意度"]'::jsonb, '卫生状况', '整体满意度', NULL),
('680280e8e3c98b0941765e26', '前台服务很贴心，酒店设施很好，卫生干净。', '["https://dimg04.c-ctrip.com/images/0231s12000b081lkq026C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231o12000b081iuf7306_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000b081j1146CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000b081iuj7E8E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000b081lf2A894_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000b081jgk9299_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-20', '花园大床房', '大床房', '情侣出游', 20, 0, 9, 5, '["前台服务","卫生状况"]'::jsonb, '前台服务', '卫生状况', NULL),
('680280e8e3c98b0941765e27', '非常用心的管理，虽然是较老牌的酒店，但是周到的服务和人文关怀还是很到位的', '["https://dimg04.c-ctrip.com/images/0234j12000asxirvyAB21_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000asxjbr14208_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000asxes6o40A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-03-23', '花园大床房', '大床房', '朋友出游', 36, 0, 33, 6, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('680280e8e3c98b0941765e28', '老酒店了，即便新装修过，也比较一般。
主要还是2楼的餐厅好。', '["https://dimg04.c-ctrip.com/images/0231o12000at0519dD971_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230112000at01vz801F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000at067c2FAB9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000at09pgh51B4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-03-24', '红棉双床套房', '套房', '商务出差', 30, 0, 174, 4, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('680280e8e3c98b0941765e29', '7年前带家人来访广州住在花园酒店，当时对酒店的优雅环境和良好服务印象深刻。这次在广州游玩还是住在了花园酒店，体验还是和上次一样的好。入住时前台Justin热心地帮我们升级了有瀑布景观的房间，还赠送了早餐。和朋友在荔湾亭餐厅品尝到了地道精致的早茶。', '["https://dimg04.c-ctrip.com/images/0233912000aquas4p2867_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-06', '红棉大床套房', '套房', '家庭亲子', 123, 0, 1, 9, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('680280e8e3c98b0941765e2a', '酒店环境别有风格，卫生管理都非常到位，工作人员热情有礼，酒店美食应有尽有，值得选择的五星酒店??', '["https://dimg04.c-ctrip.com/images/0230x12000aomll4r4250_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-17', '花园双床房', '双床房', '情侣出游', 48, 0, 12, 6, '["整体满意度","卫生状况","餐饮设施"]'::jsonb, '整体满意度', '卫生状况', '餐饮设施'),
('680280e8e3c98b0941765e2b', '服务、早餐、环境都很不错！健身设施很齐全！', '["https://dimg04.c-ctrip.com/images/0232n12000aw3c2t13E6C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235l12000aw3i7d1D81D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232x12000aw3h3289C91_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000aw3ij0m9CC4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000aw36ipl11EA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000aw37lc00404_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000aw3b8oz301C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000aw3bnx3D1AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-09', '花园大床房', '大床房', '商务出差', 21, 0, 7, 5, '["餐饮设施","公共设施","整体满意度"]'::jsonb, '餐饮设施', '公共设施', '整体满意度'),
('680280f3e3c98b0941765e2c', '前台Betty真的超级无敌好哇??
看我娃蔫巴蔫巴的，先是送花再送冰箱贴就是想让我娃开心起来！什么神仙前台！
本来定的红棉双床还提醒我粤韵是新装修比较适合bb，帮我升级了！还送了洗护哈哈哈哈哈
而且会问你出行计划，帮你推荐地方；酒店的服务设施?营业时间都很好的告知了！还有酒店26个打卡点推荐哈哈哈哈哈哈
房间分区设计规划合理，有个小客厅适合带娃父母半夜吃宵夜，就是没浴缸可惜啦！而且空调会一直对头吹，带娃要注意一下。
酒店一步一景，完全逛不完；
瀑布餐厅的早餐就一般咯，但服务人员都十分nice！
