('680280f3e3c98b0941765e2d', '非常棒的体验，我们到的比较晚，前台小姐姐帮升级了套房，床很舒服，酒店的餐厅也非常不错，早餐很丰富，服务很好！', '["https://dimg04.c-ctrip.com/images/0235812000alswydeD483_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000alsprx698D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000alsmffz2067_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-06', '花园大床房', '大床房', '朋友出游', 54, 0, 1, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('680280f3e3c98b0941765e2e', '吃的还行，房内设施一般，柜子顶部差不多掉落', '["https://dimg04.c-ctrip.com/images/0236512000avzk66uAD7E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-04-09', '花园大床房', '大床房', '商务出差', 21, 0, 15, 5, '["房间设施","餐饮设施"]'::jsonb, '房间设施', '餐饮设施', NULL),
('680280f3e3c98b0941765e2f', '花园酒店位于广州繁华心庄之地，大堂金碧辉煌及人来人往，房间里却宁静的像在山中，体现了安全感，服务员在面对交流时都是弯腰状态，非常有礼貌！', '["https://dimg04.c-ctrip.com/images/0231612000afct1o6D84E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000afcsy1iD576_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000afct1oz560A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000afct1p9ACF2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-12', '花园大床房', '大床房', '朋友出游', 68, 0, 12, 8, '["安静程度","前台服务","整体满意度"]'::jsonb, '安静程度', '前台服务', '整体满意度'),
('680280f3e3c98b0941765e30', '第二次入住广州花园酒店，这次也入住非常场愉快，Kiki服务非常贴心，本次也体验到了房型升级的服务，很开心～', '["https://dimg04.c-ctrip.com/images/0236u12000bbkhsdmC21D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000bbksckqAFF5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000bbkfmg85504_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-30', '花园大床房', '大床房', '独自旅行', 53, 0, 8, 6, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('680280f3e3c98b0941765e31', '大厅很漂亮，房间床也很软，谢谢rain', '["https://dimg04.c-ctrip.com/images/0231412000b012up847DA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-19', '花园大床房', '大床房', '家庭亲子', 19, 0, 2, 4, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('680280f3e3c98b0941765e32', '很满意服务很好，老牌五星级硬件有点老化，但是服务很周到。好评', '["https://dimg04.c-ctrip.com/images/0236912000asjx85k50D5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000asjwna204C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000asjvppoCF32_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000asjx85lF4F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000asjttgkDEF9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-20', '红棉大床套房', '套房', '情侣出游', 30, 0, 24, 6, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('680280f3e3c98b0941765e33', '可能是春节开放爆满旅游，除了前台等开房以外其余我觉得都不错，毕竟是老酒店了，有经验有各种应对流程。下次还会选住。', '["https://dimg04.c-ctrip.com/images/0234s12000ajg3nf48A3D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000ajg5udz7B43_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000ajfz68i353A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-30', '红棉大床套房', '套房', '家庭亲子', 56, 0, 8, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680280f3e3c98b0941765e34', '花园酒店给我惊喜太多了。不要担心老旧，一点问题都没有。位置绝佳，交通方便。下午茶小点心很好吃，有水准！必须表扬服务，这才是酒店最牛的地方。从办理入住，到锦鲤下午茶餐厅，几个小姐姐服务贴心周到，柔声细语，退房方便，小玉姑娘还送了孩子小礼物。强烈推荐！！', '["https://dimg04.c-ctrip.com/images/0236412000c1k158nFE08_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000c1k747kEAB6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233k12000c1k23ib1C77_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000c1k5n5vE43B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000c1k91udFE0C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-31', '花园大床房', '大床房', '家庭亲子', 125, 0, 2, 9, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('680280f3e3c98b0941765e35', '不错一直住花园酒店', '["https://dimg04.c-ctrip.com/images/0231c12000b6ke2hk229B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-08', '城央绿意大床房', '大床房', '情侣出游', 9, 0, 1, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('680280fee3c98b0941765e36', '常被亲友问为啥每次到广州 花园酒店都是首选？我觉得虽然建成多年 但这里仍然是卓越的经典酒店代表 室内设施维护的极佳-至今大堂和花园都是熠熠生辉的存在！这里服务多年以来也是保持优秀，从门童到礼宾客房都彬彬有礼，即便北上深住惯国际品牌酒店比较下也会对花园的水准折服；前台接待是酒店的灵魂人物，这次接待的Yedda令人印象深刻！看到我们家庭入住就主动找出我的会员号，给予升级服务，家人很惊喜，更加固花园粉丝地位！酒店拥有米其林两星的泰安门，以及经典茶楼荔湾亭，加之市中心淘金的地段也是餐厅咖啡密布，粤菜黄埔军校利苑就在旁边，试问如今哪家国际品牌在广州能拥有如此丰富的经典配套资源！', '["https://dimg04.c-ctrip.com/images/0236v12000agtma3p0F78_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-18', '花园双床房', '双床房', '其他', 287, 0, 9, 9, '["整体满意度","前台服务","周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套'),
('680280fee3c98b0941765e37', '每次来广州都是入住花园酒店；一如既往的贴心服务；尊享行政礼遇；感谢kiki赠送给女儿的小礼物和忘记名字的小姐姐升级的客房；顶级白金五星级酒店实至名归；强力推荐！', '["https://dimg04.c-ctrip.com/images/0234o12000aqtaduk44B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000aqtajji85E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000aqtaiqqA6AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-06', '红棉双床套房', '套房', '商务出差', 80, 0, 2, 8, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680280fee3c98b0941765e38', '真的很好 比起其他连锁五星多了很多岭南当地的特色 十分精致 尤其是前台Viria 很热心 入住很顺利', '["https://dimg04.c-ctrip.com/images/023162234bf9md8m80613_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-05', '花园大床房', '大床房', '商务出差', 50, 0, 6, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680280fee3c98b0941765e39', '非常好的一家酒店，有文化有历史，有自己的酒店博物馆，周边可逛的地方非常多，吃饭交通都非常方便，后花园很优秀！', '["https://dimg04.c-ctrip.com/images/0233212000apgm6xm10C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000apgi949FC9C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-24', '花园双床房', '双床房', '家庭亲子', 54, 0, 28, 7, '["周边配套","交通便利性","整体满意度"]'::jsonb, '周边配套', '交通便利性', '整体满意度'),
('680280fee3c98b0941765e3a', '第三次入住，五星级酒店的服务名不虚传，房间升级，瀑布餐厅和锦鲤酒吧都去打卡，假期愉快完美！', '["https://dimg04.c-ctrip.com/images/0233n12000anracpg2D40_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000anradrk4CD0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v12000anra88jC2B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000anradt1BAC8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-12', '红棉大床套房', '套房', '情侣出游', 45, 0, 4, 7, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('680280fee3c98b0941765e3b', '下次来广州再住哦', '["https://dimg04.c-ctrip.com/images/0236612000b4zkkqo9A4A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-02', '红棉双床套房', '套房', '朋友出游', 8, 0, 12, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('680280fee3c98b0941765e3c', '酒店的JESSIE人非常好，还给我们升了房间，非常满意的住店体验', '["https://dimg04.c-ctrip.com/images/0234o12000ar6a44rD32A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-09', '城央绿意大床房', '大床房', '其他', 32, 0, 1, 5, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('680280fee3c98b0941765e3d', '硬件非常不错，花园和酒廊都是非常不错的。', '["https://dimg04.c-ctrip.com/images/0230512000aua9lar8EB9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000auald2s10D5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000auapeb5EA1B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000auanh9kE17E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233k12000auae3peFAF3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000auahtgcA779_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-02', '花园大床房', '大床房', '商务出差', 20, 0, 3, 4, '["公共设施","餐饮设施"]'::jsonb, '公共设施', '餐饮设施', NULL),
